class Player:
    def __init__(self, color):
        self.color = color
        self.opponent = "black" if color == "white" else "white"

    def move(self, board, from_pos, to_pos):
        row_from, col_from = ord(from_pos[0]) - ord('a'), int(from_pos[1]) - 1
        row_to, col_to = ord(to_pos[0]) - ord('a'), int(to_pos[1]) - 1

        piece = board.board[row_from][col_from]
        if piece and piece.color == self.color:
            board.board[row_to][col_to] = piece
            board.board[row_from][col_from] = ''
        else:
            print("Invalid move, try again.")
